var e=[{id:`L2_1`,type:`dialog`,speaker:`POOR_NPC_NULL_BOSS`,text:{KOREA:`크으윽… 내가… 엘릭서를 쓰고도 힘에서 밀리다니…?`,JPN:`くううっ……俺が……エリクサーを飲んでも力で負けるとは……？`,ENG:`Kggh... I lost... even with the Elixir...?`,TWN:`唔…我用了聖水還是打不過你…？`},stage:{bg:`WORKSHOP`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`무술 실력을 보아하니 그대는 백서의 사람이 아닌 것 같구려.`,JPN:`武術の実力から見ると、貴殿は白西の者ではないようですね。`,ENG:`Observing your skills, I have confirmed that you are not with White West.`,TWN:`在下看你的武功實力，似乎不是白西的人。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`묻겠소. 누가 날 데려오라고 사주한 것이오?`,JPN:`問いましょう。誰から自分を連れてくるようにと頼まれたのですか？`,ENG:`Answer me. Who ordered you to kidnap me?`,TWN:`敢問，是誰指使你把我抓來這裡的？`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`POOR_NPC_NULL_BOSS`,text:{KOREA:`머, 멍청하긴. 그렇게 물어보면 누가 대답을 해주겠대?`,JPN:`ば、バカだな。そう聞かれても答えるわけにはいかねえよ。`,ENG:`H-how stupid are you? You think I'm gonna answer that?!`,TWN:`
當，當我傻子嗎？你問我，我就要回答你嗎？`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`POOR_NPC_NULL_BOSS`,text:{KOREA:`으아악…!!!`,JPN:`ぐわああっ……！！！`,ENG:`Aaack...!`,TWN:`呃啊啊啊…！！！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`이렇게 하면 말할 거요?`,JPN:`こうすれば答えていただけますか？`,ENG:`Does this make you feel more inclined to answer?`,TWN:`那這樣呢？`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`POOR_NPC_NULL_BOSS`,text:{KOREA:`마… 말… 못해… 말했다간 난 죽은 목숨이라고…`,JPN:`は……話せ……ねえ……話したら俺は死ぬ……`,ENG:`N-never...! I'm a dead man if I tell you anything...`,TWN:`我…我…我不能說…要是我告訴你的話，我也別想活命…`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`본인은 타혈법에 능통하다오.`,JPN:`自分は点穴に精通しています。`,ENG:`I have mastered nerve strikes.`,TWN:`在下精通穴道。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`바란다면 죽음보다 더한 아홉 가지 고통을 동시에 느끼게 해주겠소.`,JPN:`お望みなら、死よりもむごい9つの苦痛を同時に感じさせてあげましょう。`,ENG:`I shall let you feel nine kinds of pain far worse than death itself, if that is what you wish.`,TWN:`你想試試的話，在下可以讓你同時感受到九種生不如死的痛苦。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`POOR_NPC_NULL_BOSS`,text:{KOREA:`으… 으… 절대로…`,JPN:`う……う……絶対に……`,ENG:`Ngh... I'll... never–`,TWN:`呃…呃…我不能…`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`POOR_NPC_NULL_BOSS`,text:{KOREA:`끼야아아아아아아앗!!!!`,JPN:`ぎゃあああああああっ！！！！`,ENG:`AAAAAGH!!!!`,TWN:`呃啊啊啊啊啊啊！！！`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`마지막까지 실토를 하지 않다니… 그대의 인내심은 인정할 만 하구려.`,JPN:`最後まで口を割らないとは……貴殿の忍耐力は認めざるを得ません。`,ENG:`Not talking, I see... I admire your tolerance to pain.`,TWN:`嘴巴真緊…我承認你的忍耐力可佳。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`POOR_NPC_NULL_BOSS`,text:{KOREA:`끄으으으… 윽…`,JPN:`くううう……うっ……`,ENG:`Krrrrgh... Ngh.`,TWN:`呃呃呃…呃…`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`POOR_NPC_NULL_B`,text:{KOREA:`두목이… 아까부터 계속 뭔가 말하려는 것 같았는데…`,JPN:`親分……さっきからずっと何か話そうとしてたみたいだったけど……`,ENG:`I think... boss was trying to say something...`,TWN:`老大…好像有什麼話想說…`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`POOR_NPC_NULL_A`,text:{KOREA:`입만 뻐끔거리며 고통스러워하다가 기절했어.`,JPN:`口だけ動かしながら苦しんで気絶しちまった。`,ENG:`He kept mouthing something, but fainted due to the pain.`,TWN:`但他好像來不及說，就痛到暈過去了。`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`그대들도 덤빌 셈이요?`,JPN:`貴殿らもかかってくるつもりですか？`,ENG:`Do you wish to challenge me as well?`,TWN:`你們也想挑戰嗎？`},stage:{bg:`WORKSHOP`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};